blocks.body:
{
    "level": "B1",
    "intro": "W tym temacie nauczysz się tworzyć <strong>stronę bierną z czasownikami posiadającymi dwa załączniki</strong>: dawać, wysyłać, oferować, mówić, pokazywać i inne. Dowiesz się, która opcja jest bardziej naturalna: „Dano mu książkę” czy „Dano mu książkę”.",
    "rules": [
        {
            "label": "Aktywny",
            "color": "emerald",
            "text": "Stan aktywny z dwiema aplikacjami:",
            "example": "They gave him a book."
        },
        {
            "label": "Pasywny 1",
            "color": "blue",
            "text": "Osoba jako podmiot (częściej):",
            "example": "He was given a book."
        },
        {
            "label": "Pasywny 2",
            "color": "rose",
            "text": "Rzecz jako temat (rzadko):",
            "example": "A book was given to him."
        }
    ]
}

{
    "title": "1. Co to są czasowniki dwuobiektowe?",
    "intro": "Niektóre czasowniki mają dwa załączniki — pośredni (dopełnienie pośrednie) i bezpośredni (dopełnienie bezpośrednie):",
    "items": [
        {
            "label": "Obiekt pośredni",
            "title": "Zastosowanie pośrednie",
            "subtitle": "KOGO? - zwykle osoba (on, ona, ja)"
        },
        {
            "label": "Obiekt bezpośredni",
            "title": "Bezpośrednia aplikacja",
            "subtitle": "CO? – zwykle rzecz (książka, pieniądze)"
        },
        {
            "label": "Struktura",
            "title": "S + V + IO + DO",
            "subtitle": "Dali mu (IO) książkę (DO)."
        },
        {
            "label": "Alternatywny",
            "title": "S + V + DO + do/dla + IO",
            "subtitle": "Dali mu książkę."
        }
    ]
}

{
    "title": "2. Dwa warianty strony biernej",
    "sections": [
        {
            "label": "Opcja 1: Osoba jest podmiotem",
            "color": "emerald",
            "description": "<strong>Przedmiot pośredni</strong> (osoba) staje się podmiotem. Jest to <strong>częsta</strong> i bardziej naturalna opcja.",
            "examples": [
                {
                    "en": "Active: They gave him a book.",
                    "ua": "Dali mu książkę."
                },
                {
                    "en": "Passive: He was given a book.",
                    "ua": "Dano mu książkę. (skoncentruj się na „on”)"
                },
                {
                    "en": "Active: Someone sent her a letter.",
                    "ua": "Ktoś wysłał jej list."
                },
                {
                    "en": "Passive: She was sent a letter.",
                    "ua": "Wysłano do niej list."
                }
            ]
        },
        {
            "label": "Opcja 2: Rzecz jest podmiotem",
            "color": "sky",
            "description": "<strong>Przedmiot bezpośredni</strong> (rzecz) staje się podmiotem. Przyimek <strong>do/for</strong> jest wymagany.",
            "examples": [
                {
                    "en": "Active: They gave him a book.",
                    "ua": "Dali mu książkę."
                },
                {
                    "en": "Passive: A book was given to him.",
                    "ua": "Książka została mu przekazana. (skoncentruj się na „książce”)"
                },
                {
                    "en": "Active: Someone sent her a letter.",
                    "ua": "Ktoś wysłał jej list."
                },
                {
                    "en": "Passive: A letter was sent to her.",
                    "ua": "Wysyłano do niej listy."
                }
            ]
        },
        {
            "label": "Który wybrać?",
            "color": "amber",
            "description": "Opcja 1 (osoba – podmiot) jest <strong>bardziej naturalna</strong> w języku angielskim. Opcja 2 — gdy nacisk położony jest na rzeczy.",
            "examples": [
                {
                    "en": "She was offered a job. ✓ (звичайно)",
                    "ua": "Zaproponowano jej pracę."
                },
                {
                    "en": "A job was offered to her. (акцент на \"роботу\")",
                    "ua": "Zaproponowano jej pracę."
                }
            ]
        }
    ]
}

{
    "title": "3. Typowe czasowniki dwuobiektowe",
    "sections": [
        {
            "label": "dać / wysłać / przynieść",
            "color": "emerald",
            "description": "Czasowniki <strong>przekaz</strong>: dawać, wysyłać, przynosić.",
            "examples": [
                {
                    "en": "He was given a warning.",
                    "ua": "Otrzymał ostrzeżenie."
                },
                {
                    "en": "She was sent the documents.",
                    "ua": "Dokumenty zostały jej przesłane."
                },
                {
                    "en": "They were brought refreshments.",
                    "ua": "Przynoszono im napoje."
                }
            ]
        },
        {
            "label": "oferować / obiecywać / pożyczać",
            "color": "blue",
            "description": "Czasowniki ofertowe: oferować, obiecywać, pożyczać.",
            "examples": [
                {
                    "en": "She was offered a promotion.",
                    "ua": "Zaproponowano jej awans."
                },
                {
                    "en": "He was promised a raise.",
                    "ua": "Obiecano mu podwyżkę."
                },
                {
                    "en": "They were lent some money.",
                    "ua": "Pożyczono im pieniądze."
                }
            ]
        },
        {
            "label": "powiedz / pokaż / naucz",
            "color": "sky",
            "description": "Czasowniki informacyjne: powiedz, pokaż, naucz.",
            "examples": [
                {
                    "en": "He was told the truth.",
                    "ua": "Powiedziano mu prawdę."
                },
                {
                    "en": "She was shown the new system.",
                    "ua": "Pokazano jej nowy system."
                },
                {
                    "en": "We were taught English grammar.",
                    "ua": "Uczono nas gramatyki języka angielskiego."
                }
            ]
        },
        {
            "label": "wynagrodzenie/nagroda/dotacja",
            "color": "amber",
            "description": "Czasowniki nagradzające: płacić, nagradzać, przyznawać.",
            "examples": [
                {
                    "en": "She was paid a bonus.",
                    "ua": "Wypłacono jej premię."
                },
                {
                    "en": "He was awarded a medal.",
                    "ua": "Został odznaczony medalem."
                },
                {
                    "en": "They were granted permission.",
                    "ua": "Dostali pozwolenie."
                }
            ]
        }
    ]
}

{
    "title": "4. Transformacja aktywna → pasywna",
    "intro": "Jak zamienić zdanie z dwoma dopełnieniami na stronę bierną:",
    "rows": [
        {
            "en": "Active: They gave her a gift.",
            "ua": "IO: ona, DO: prezent",
            "note": "Passive 1: She was given a gift. ✓"
        },
        {
            "en": "Active: They gave her a gift.",
            "ua": "IO: ona, DO: prezent",
            "note": "Passive 2: A gift was given to her."
        },
        {
            "en": "Active: Someone sent him a message.",
            "ua": "IO: on, DO: wiadomość",
            "note": "Passive: He was sent a message. ✓"
        },
        {
            "en": "Active: They offered us help.",
            "ua": "IO: my, DO: pomoc",
            "note": "Passive: We were offered help. ✓"
        }
    ],
    "warning": "📌 W języku angielskim słowo <strong>osoba jako temat</strong> brzmi bardziej naturalnie!"
}

{
    "title": "5. Przyimek „do” vs „dla”",
    "sections": [
        {
            "label": "do - przenieść",
            "color": "emerald",
            "description": "Użyj słowa <strong>do</strong> z czasownikami przekazującymi (dawać, wysyłać, mówić, pokazywać, oferować).",
            "examples": [
                {
                    "en": "A book was given to him.",
                    "ua": "Książka została mu przekazana."
                },
                {
                    "en": "The letter was sent to her.",
                    "ua": "List został do niej wysłany."
                },
                {
                    "en": "The news was told to everyone.",
                    "ua": "Wiadomość została przekazana wszystkim."
                }
            ]
        },
        {
            "label": "dla - dla korzyści",
            "color": "blue",
            "description": "Używaj słowa <strong>for</strong> z czasownikami „dla korzyści” (kup, zrób, ugotuj, znajdź, zdobądź).",
            "examples": [
                {
                    "en": "A cake was made for her.",
                    "ua": "Upieczono dla niej ciasto."
                },
                {
                    "en": "A ticket was bought for him.",
                    "ua": "Bilet został kupiony dla niego."
                },
                {
                    "en": "A solution was found for them.",
                    "ua": "Znaleziono dla nich rozwiązanie."
                }
            ]
        }
    ]
}

{
    "title": "6. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie przyimka, gdy rzecz jest podmiotem.",
            "wrong": "A book was given him.",
            "right": "✅ A book was given to him."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Przyimek zbędny, gdy podmiotem jest osoba.",
            "wrong": "He was given to a book.",
            "right": "✅ He was given a book."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Pomieszanie słów „do” i „za”.",
            "wrong": "A cake was made to her.",
            "right": "✅ A cake was made for her."
        }
    ]
}
